UPDATE FILES
SET    FILE_NAME  = #{file_name},
       FILE_EXT   = #{file_ext},
       SFILE_NAME = #{sfile_name}
WHERE  TEAM_IDX   = #{team_idx}

UPDATE MEMBER_TEAM
SET    POSITION = #{position},
       BACK_NUM = #{back_num, jdbcType=NUMERIC}
WHERE  MEMBER_IDX = #{member_idx}
AND    TEAM_IDX   = #{team_idx}

