DELETE FROM MEMBER_TEAM
WHERE  MEMBER_IDX = #{member_idx}
AND    TEAM_IDX   = #{team_idx}

mapper.select:
SELECT JOIN_STATUS FROM MEMBER_TEAM
WHERE  MEMBER_IDX = #{member_idx}
AND    TEAM_IDX   = #{team_idx}

mapper.update:
UPDATE MEMBER_TEAM
SET    JOIN_STATUS = #{join_status}
WHERE  MEMBER_IDX = #{member_idx}
AND    TEAM_IDX   = #{team_idx}

mapper.select:
SELECT COUNT(*) FROM MEMBER_TEAM
WHERE team_idx    = #{team_idx}
AND   member_idx != #{member_idx}
AND   join_status = 1
